import { Component, Host, h } from '@stencil/core';

/**
 * This component acts as a wrapper for the popover which holds, arrow (caret),
 * popover body (kds-popover-body) and dismiss button
 */
@Component({
  tag: 'kds-popover-wrapper',
  styleUrl: 'kds-popover-wrapper.css'
})
export class KdsPopoverWrapper {
  render() {
    return (
      <Host class='kds-popover-wrapper'
        role='dialog'
        aria-describedby='kdsPopOverContent'
        aria-label='kds-popover'>
        <slot />
      </Host>
    );
  }
}
